import{_ as i,o as n,c as l,ag as s}from"./chunks/framework.DXGyWiRo.js";const r="/images/uebung090.jpg",t="/images/uebung094.jpg",k=JSON.parse('{"title":"Übung Lektion 57","description":"","frontmatter":{},"headers":[],"relativePath":"lektionen/uebung57.md","filePath":"lektionen/uebung57.md"}'),o={name:"lektionen/uebung57.md"};function g(a,e,d,m,u,h){return n(),l("div",null,[...e[0]||(e[0]=[s('<div class="info custom-block github-alert"><p class="custom-block-title">Zitierweise &amp; Rechte</p><p>Dieses Kapitel ist Teil des Sanskritkurses. Details zum Copyright und zur Zitierweise der Ursprungsfassung siehe: <a href="/impressum">Impressum &amp; Copyright</a></p></div><h1 id="ubung-lektion-57" tabindex="-1">Übung Lektion 57 <a class="header-anchor" href="#ubung-lektion-57" aria-label="Permalink to &quot;Übung Lektion 57&quot;">​</a></h1><p>Auflösung ohne Anspruch auf Vollständigkeit!</p><p>A) Übersetzen und bestimmen Sie ohne Hilfsmittel folgende Formen und bilden Sie die entsprechenden Aoristformen. Außer bei Kausativen und Wurzeln, die den s-Aorist bilden, ist in Klammer die Klasse des entsprechenden Aorists angegeben:</p><ol><li>पेचिथ - पच् 1U 2.sg.P.Perf du gartest - अपाक्षीः</li><li>अवक् (३) - वच् 2P 2.3.sg.P.Imp du sprachst / er sprach - अवोचः । अवोचत्</li><li>सोष्यसि - सु 1/2P 2.sg.Fut.P du wirst dich fortpflanzen - असौषीः</li><li>छिन्दे - छिद् 7U 1.sg.Ind.Präs.Ā ich schneide ab - अच्छित्सि</li><li>कुरुषे - कृ 8U 2.sg.Ind.Päs.Ā du tust im eigenen Interesse - अकृथाः</li><li>आधत्ते - आ-धा 3Ā 3.sg.Ind.Präs.Ā du setzst hin - आधित</li><li>पद्यते - पद् 4Ā 3.sg.Ind.Präs.Ā er geht - अपादि</li><li>जिगाय - जि 1P 1.3.sg.Perf.P ich / er siegte - अजैषीत्</li><li>जिघ्रामः (१,६) - घ्रा 1P 1.pl.Ind.Präs.P wir riechen - अघ्रास्म । अघ्राम</li><li>शासति (२) - शास् 2P 3.pl.Ind.Präs.P sie befehlen - अशिषन्</li><li>स्तुवे - स्तु 2U 1.sg.Ind.Präs.Ā ich preise in meinem Interesse - अस्तोषि</li><li>दिग्धे - दिह् 2U 3.sg.Ind.Präs.Ā er bestreicht im eigenen Interesse - अदिग्ध</li><li>प्लवध्वे - प्लु 1Ā 2.pl.Ind.Präs.Ā ihr schwimmt - अप्लोढ्वम्</li><li>तस्थिथ (१) - स्था 1P 2.sg.Perf.P du standest - अस्थाः</li><li>बिभ्यति - भी 3P 3.pl.Ind.Präs.P sie fürchten - अभैषुः</li><li>ततर्प - तृप् 4/6P 1.3.Perf.P ich / er sättigte mich - अतार्प्सम् । अत्राप्सम् । अतार्प्सीत् । अत्राप्सीत्</li><li>जुहुथ - हु 3P 2.pl.Ind.Präs.P ihr gießt ins Opferfeuer - अहौष्ट</li><li>ऊषुः - वस् 1P 3.pl.Perf.P sie wohnten - अवात्सुर्</li><li>ससर्जिथ - सृज् 6P 2.sg.Perf.P du hast erschaffen - अस्राक्षीः</li><li>लिल्यिरे - ली 4Ā 3.pl.Perf.Ā sie haben sich angeschmiegt - अलेषत । अलासत</li><li>अत्याजयम् - त्यज् 1P 1.sg.Impf.P.Kaus ich ließ verlassen - अतित्यजम्</li><li>सिध्यथ (२) - सिध् 4P 2.pl.Ind.Präs.P ihr seid ans Ziel gekommen - असिधत</li><li>निन्य - नी 1U 2.pl.Perf.P ihr habt geführt - अनैष्ट</li><li>कर्षन्ति - कृष् 1P 3.pl.Ind.Präs.P sie ziehen - अकार्क्षुः । अक्राक्षुः</li><li>अप्रच्छयन् - प्रच्छ् 6P 3.pl.Impf.P.Kaus. sie ließen fragen - अपप्रच्छन्</li></ol><p><img src="'+r+'" alt=""><br> Abb.: वारानास्यां गङ्गायामप्लोढ्वम्<br> [Bildquelle: juicyrai. -- <a href="http://www.flickr.com/photos/wink/184339799/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/wink/184339799/</a>. -- Zugriff am 2009-03-11. -- <a href="http://creativecommons.org/licenses/by-nc-sa/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nuttzung, share alike)]</p><p>B) Übersetzen und bestimmen Sie folgende Formen:</p><ol><li>चेलुः - चल् 1P 3.pl.Perf.P sie sind in Bewegung geraten</li><li>जन्तुः - जन्तु m. Nom.sg. das Geschöpf, die Leute</li><li>अश्वसीत् - श्वस् 2P 3.sg.Impf.P er blies</li><li>ज्येष्ठायाः - ज्येष्ठ 3 Gen.Abl.sg.f. (von) der besten / der ältesten</li><li>संयक् - Adv. richtig</li><li>असे - असि m. Vok.sg. Schwert!</li><li>असि - अस् 2P 2.sg.Ind.Präs.P du bist</li><li>अचैष्ट - चि 5U 3.sg.Aor(4).Ā er hat im eigenen Interesse aufgeschichtet</li><li>अचेष्ट - चि</li><li>अभग्नम् अ + PPP von भञ्ज् 7P Nom.Akk.sg.n.Akks.sg.m. das unzerbrochene / den unzerbrochenen</li><li>भस्म - भस्मन् n. Nom.Akk.sg.n. die Asche</li><li>हवींषि - हविस् n. Nom.Akk.Vok.pl. die Opfergabe</li><li>अद्राक्षीः - दृश् 4P 2.sg.Aor(4).P du sahst</li><li>शनैः - Adv. langsam, allmählich</li><li>अपन्थाः - अ-पथ् m. Nom.,Vok.sg. der Nicht-Weg, der Unweg</li><li>शत्रुह - शत्रुहन् 3 Nom.Akk.sg.n. das Feinde-tötende</li><li>उदासीने - उदासीन 3 indifferent Lok.sg.m.n.Vok.sg.f.Nom.Akk.Vok.du.n.f.</li><li>कनीयान् - Nom.sg.m.Komparativ der kleinere</li><li>कन्याम् - कन्या f. Akk.sg. das Mädchen</li><li>आरम् - ऋ 1/9P 1.sg.Aor(2)P ich ging</li><li>रिपू - रिपु m. Nom.Akk.Vok.du. die beiden Betrüger / Feinde</li><li>अदात् - दा 3U 3.sg.Aor(1).P er gab</li><li>आदत् -अद् 2P 3.sg.Impf.P er aß</li><li>अवोढ - वह् 1U 3.sg.Aor(4).Ā er fuhr im eigenen Interesse ; PPP zu अव-वह् Vok.Sg.m.n. Herabgeführter!</li><li>अवोचम् - वच् 2P 1.sg.Aor(3).P ich sprach</li><li>दिक् - दिश् f. Nom.sg. die Richtung / Gegend</li><li>शुनोः - श्वन् m. Gen.Lok.du. der / in den beiden Hunde(n)</li><li>यते - यति m. Vok.sg. Asket! ; PPP zu यम् 1P Lok.sg.m.n.Vok.sg.f.Nom.Akkk.Vok.du.n.f. gehalten ; यत् 1Ā 1.sg.Ind.Präs.Ā ich strebe ; Part.Präs.P zu इ 2P Dat.sg.m.n. dem gehenden</li><li>येते - यत् 1Ā 1.3.sg.Perf.Ā ich / er strebte</li><li>याते - PPP zu या 2P gegangen Lok.sg.m.n.Vok.sg.f.Nom.Akk.Vok.du.n.f. ; PartPräsP zu या 2P Dat.sg.m.n. dem gehenden</li><li>चतस्रः - चतुर् 3 Nom.Akk,Vok.pl.f. vier</li><li>परंपरायै - परंपरा f. Dat.sg. der Sukzession</li><li>विमलाभ्याम् - विमल 3 Instr.Dat.Abl.du.m.f.n. durch die schmutzfreien /  ...</li><li>ते - त्वम् Dat.Gen.enklit. dir / dein ;  तद् 3 dieses Nom.pl.m.Nom.Akk.du.f.n.</li><li>रजसि - रजस् n. Lok.sg.n. in der Helle</li><li>रजसी - रजस् n. Nom.Akk.Vok.du. die beiden Hellen</li><li>विक्रेढ्वम् - वि-क्री 9Ā 2.pl.Ā.Injunktiv.Aor(4) verkauft [+ मा nicht]</li><li>युष्मत् - युष्मद् Abl.pl. von euch</li><li>अघम् - अघ n. Nom.Akk.Vok.sg. das Übel ; अघ 3 Akk.sg.m. den Bösen</li><li>अभुक्थाः - भुज् 7U 2.sg.Aor(4).Ā du hast im eigenen Interesse gegessen</li><li>उत्थानाय - उत्थान n. Dat.sg. dem Aufstehen</li><li>अलुम्पत - लुप् 6U 2.pl.Impf.P3.sg.Impf.Ā ihr zerbracht / er zerbrach im eigenen Interesse</li><li>अलुपत - लुप् 6U 2.pl.Aor(2).P ihr zerbracht</li><li>अलुप्त - लुप् 6U 3.sg.Aor(4).Ā er zerbrach im eigenen Interesse ;  अ + PPP zu लुप् 6U Vok.sg. Ungebrochener!</li><li>अलुप्तम् - अ + PPP लुप् Nom.Akk.sg.n.Akk.sg.m. dem Ungebrochenen / das Ungebrochene</li><li>वसिष्ठे - Superl. zu वसुमन्त् 3 Lok.sg.m.n.Vok.sg.f.Nom.Akk.Vok.du.n.f. im reichsten / ...</li><li>वर्षिष्ठे - Superl. zu वृद्ध 3 Lok.sg.m.n.Vok.sg.f.Nom.Akk.Vok.du.n.f. im ältesten / ...</li><li>अक्षैष्म - क्षि 1/5/9P 1.pl.Aor(4).P wir vernichteten</li><li>अहृत - हृ 1U 3.sg.Aor(4/1).Ā er hielt ; अ + PPP zu हृ 1U Vok.sg.m.n. Ungehaltener!</li><li>कामधुग्भिः - कामदुह् f. Instr.pl. durch Wunschkühe</li><li>अमुत्र - Adv. dort</li><li>पत्युः - पति m. Abl.Gen. des Gatten / von dem Gatten</li><li>क्षेपीयन् - Komparativ zu क्षिप्र 3 Vok.sg.m. Sehr Schneller!</li><li>आदि्षि - आ-दा 3Ā 1.sg.Aor(4).Ā ich nahm</li><li>पाणी - पाणि m. Nom.Akk.Vok.du. beide Hände</li><li>अस्प्राक्षम् - स्पृश् 6P 1.sg.Aor(4).P ich berührte</li></ol><p><img src="'+t+'" alt=""><br> Abb.: पाणी धूपं कुरुतः ॥<br> Mysuru = ಮೈಸೂರು<br> [Bildquelle: Jonathan Camuzo. -- <a href="http://www.flickr.com/photos/jonathancamuzo/2870689892/" target="_blank" rel="noreferrer">http://www.flickr.com/photos/jonathancamuzo/2870689892/</a>. -- Zugriff am 2009-03-11. -- <a href="http://creativecommons.org/licenses/by-nc-nd/2.0/deed.de" target="_blank" rel="noreferrer">Creative Commons Lizenz</a> (Namensnennung, keine kommerzielle Nutzung, keine Bearbeitung)]</p><p>Zur Lösung der <a href="./uebung58">Übungen 58 - 60</a></p>',10)])])}const c=i(o,[["render",g]]);export{k as __pageData,c as default};
